import os
from datetime import datetime

class Logger():
    def __init__(self, filename):
        self._filename = filename  # name of the output log file (e.g., 'app.log')
        
    @staticmethod
    def _format_message(msg: str) -> dict[str]:
       return {'timestamp': datetime.now().isoformat(),'level': '', 'content': msg}  # formatting message as a dictionary for easy parsing in the log file later on (e.g., timestamp, level and content). You can add more fields if needed like request_id etc..  
    
    def info(self,msg: str):        
        self._log('INFO', msg)  # logging informational message to a specified filename in the log file with current time stamp.      
          
    def error(self, msg:str)->None :         
      return self._log("ERROR", msg )   #logging errors into specific files and also provide timestamp for easy debugging purpose . 
    
        
    def _log(self, level ,msg):            
        message = Logger._format_message(msg)          
        with open (os.path.join('./', self._filename), 'a') as file:          # append mode to write logs into the logfile  .  
            file.write("[{timestamp}] [{level}] {content}\n".format(**message))    # formatting message and writing it in a specific way for easy parsing later on (e.g., timestamp, level etc.)